def count_rooms_v3(grid, color, noise_color):
    """Count rooms by repairing border and flood filling."""
    inp = np.array(grid)
    positions = np.argwhere(inp == color)
    rmin, cmin = positions.min(axis=0)
    rmax, cmax = positions.max(axis=0)

    H = rmax - rmin + 1
    W = cmax - cmin + 1

    # Create wall mask within bbox
    wall = [[False]*W for _ in range(H)]
    for r in range(H):
        for c in range(W):
            val = inp[rmin+r][cmin+c]
            if val == color:
                wall[r][c] = True

    # Repair: force entire border to be walls
    for r in range(H):
        wall[r][0] = True
        wall[r][W-1] = True
    for c in range(W):
        wall[0][c] = True
        wall[H-1][c] = True

    # Now we need to repair internal walls too
    # Find rows that are predominantly walls (internal horizontal dividers)
    # and columns that are predominantly walls (internal vertical dividers)

    # Count wall cells per row and column
    row_wall_count = [sum(1 for c in range(W) if wall[r][c]) for r in range(H)]
    col_wall_count = [sum(1 for r in range(H) if wall[r][c]) for c in range(W)]

    # Internal wall rows: non-border rows with high wall count
    # Threshold: more than half the width
    for r in range(1, H-1):
        if row_wall_count[r] >= W * 0.5:
            for c in range(W):
                wall[r][c] = True

    for c in range(1, W-1):
        if col_wall_count[c] >= H * 0.5:
            for r in range(H):
                wall[r][c] = True

    # Flood fill to count rooms (connected components of non-wall cells)
    visited = [[False]*W for _ in range(H)]
    rooms = 0

    for r in range(H):
        for c in range(W):
            if wall[r][c] or visited[r][c]:
                continue
            rooms += 1
            queue = deque([(r, c)])
            visited[r][c] = True
            while queue:
                cr, cc = queue.popleft()
                for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
                    nr, nc = cr+dr, cc+dc
                    if 0 <= nr < H and 0 <= nc < W and not wall[nr][nc] and not visited[nr][nc]:
                        visited[nr][nc] = True
                        queue.append((nr, nc))

    return rooms

